[
  {
    "id": "host-binding-exposes-unauthenticated-cli-proxy",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:759",
    "description": "`ab serve --openai --host 0.0.0.0` is accepted without any explicit remote-access guard, despite the docs describing this as localhost-only tooling. Because the endpoint has no authentication and each `/v1/chat/completions` request can launch local agent CLIs in the repository environment, an accidental non-loopback bind exposes a powerful local execution surface to the network. Require loopback hosts by default and gate non-localhost binds behind an explicit opt-in such as `--allow-remote`."
  },
  {
    "id": "unbounded-requests-spawn-expensive-subprocesses",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:294",
    "description": "`chat_completions` accepts arbitrarily large request bodies and message lists, flattens them into memory, and then starts a backend subprocess with a 120 second timeout and captured output for every request. There is no request-size cap, prompt-size cap, output cap, queueing, or concurrency limit, so a client can consume memory and worker threads or fan out many long-running CLI invocations. Add explicit limits at the proxy boundary before flattening and enforce a bounded execution queue or concurrency semaphore."
  },
  {
    "id": "prompt-passed-via-command-arguments",
    "severity": "MEDIUM",
    "category": "security",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:170",
    "description": "The Gemini, Claude, and Hermes backends pass the full user prompt through command-line arguments (`--prompt=...`, positional prompt, and `--oneshot=...`). Prompt text can contain sensitive user data and becomes visible to local process inspection, and large prompts can fail with OS argument-size errors before the backend runs. Send prompts through stdin or a temporary file with restrictive permissions instead of argv."
  },
  {
    "id": "streaming-requests-silently-return-nonstreaming-response",
    "severity": "LOW",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:294",
    "description": "The request model allows extra OpenAI fields, but `stream: true` is ignored and the endpoint returns a normal non-streaming `chat.completion` response. OpenAI-compatible clients that request streaming expect an SSE stream of chat completion chunks and may hang or fail when they receive JSON instead. Since Phase 1 is intentionally non-streaming, reject `stream=true` with a clear 400 error rather than silently changing the response shape."
  }
]

[
  {
    "id": "missing-correction-not-required",
    "severity": "MEDIUM",
    "category": "spec-compliance",
    "location": "scripts/build/linear_pipeline.py:549",
    "description": "The new item schema only requires `sentence` and `error`, while `answer`/`correction` are optional. Existing schema coverage treats an error-correction item without a corrected form as invalid, and the renderer maps the authoring `answer`/`correction` value into the component's required `correctForm`. As written, a writer can emit `sentence` plus `error` with no corrected answer, pass this gate, and produce a broken activity with an empty correction."
  },
  {
    "id": "activity-schema-correction-targets-module",
    "severity": "MEDIUM",
    "category": "correctness",
    "location": "scripts/build/linear_pipeline.py:118",
    "description": "`activity_schema` is added to `WRITER_CORRECTION_GATES`, but the writer-correction path for non-`strict_json_parse` gates is documented and implemented as `module.md`-only: the prompt receives only module content and `_apply_writer_correction` accepts a single `module.md` fence. Activity-schema failures live in `activities.yaml`, so the correction loop will route them to a path that normally cannot update the failing artifact, burn the single retry, and terminate with the same schema failure."
  }
]
